// Generated by Claude Opus 4.6

import { helpers } from '@eclipse-che/common';
import { AlertVariant, Button, Divider, Flex, FlexItem } from '@patternfly/react-core';
import { CompressIcon, CopyIcon, DownloadIcon, ExpandIcon } from '@patternfly/react-icons';
import React from 'react';
import CopyToClipboard from 'react-copy-to-clipboard';

import styles from '@/components/DevfileEditorTools/index.module.css';
import { lazyInject } from '@/inversify.config';
import { AppAlerts } from '@/services/alerts/appAlerts';
import { AlertItem } from '@/services/helpers/types';

export interface Props {
  contentText: string;
  workspaceName: string;
  title?: string;
  statusLabel?: React.ReactNode;
  isExpanded: boolean;
  readOnly?: boolean;
  onToggleExpand: () => void;
}

interface State {
  copied?: boolean;
  contentText: string;
  contentBlobUrl: string;
}

export default class DevfileEditorTools extends React.PureComponent<Props, State> {
  private copiedTimer: number | undefined;

  @lazyInject(AppAlerts)
  private readonly appAlerts: AppAlerts;

  constructor(props: Props) {
    super(props);

    this.state = {
      contentText: '',
      contentBlobUrl: '',
    };
  }

  public componentDidMount(): void {
    this.init();
  }

  public componentDidUpdate(): void {
    this.init();
  }

  private init() {
    const { contentText } = this.props;
    try {
      if (contentText !== this.state.contentText) {
        const contentBlobUrl = URL.createObjectURL(
          new Blob([contentText], { type: 'application/x-yaml' }),
        );
        this.setState({ contentText, contentBlobUrl });
      }
    } catch (e) {
      this.showAlert({
        key: 'devfile-editor-tools-create-blob-url-fails',
        variant: AlertVariant.danger,
        title: helpers.errors.getMessage(e),
      });
    }
  }

  private showAlert(alert: AlertItem): void {
    this.appAlerts.showAlert(alert);
  }

  private onCopyToClipboard(): void {
    this.setState({ copied: true });
    if (this.copiedTimer) {
      clearTimeout(this.copiedTimer);
    }
    this.copiedTimer = window.setTimeout(() => {
      this.setState({ copied: false });
    }, 3000);
  }

  public render(): React.ReactElement {
    const { workspaceName, title, statusLabel, isExpanded, readOnly, onToggleExpand } = this.props;
    const { contentText, contentBlobUrl, copied } = this.state;

    return (
      <div className={styles.editorTools}>
        {title && <span className={styles.title}>{title}</span>}
        {statusLabel && <span className={styles.statusLabel}>{statusLabel}</span>}
        <Flex>
          {!readOnly && (
            <React.Fragment>
              <FlexItem>
                <CopyToClipboard text={contentText} onCopy={() => this.onCopyToClipboard()}>
                  <Button variant="link" className={styles.button}>
                    <CopyIcon />
                    {copied ? 'Copied' : 'Copy to clipboard'}
                  </Button>
                </CopyToClipboard>
              </FlexItem>
              <Divider orientation={{ default: 'vertical' }} />
              <FlexItem>
                <Button
                  variant="link"
                  component="a"
                  className={styles.button}
                  download={`${workspaceName}.devfile.yaml`}
                  href={contentBlobUrl}
                >
                  <DownloadIcon />
                  Download
                </Button>
              </FlexItem>
              <Divider orientation={{ default: 'vertical' }} />
            </React.Fragment>
          )}
          <FlexItem>
            <Button className={styles.button} variant="link" onClick={onToggleExpand}>
              {isExpanded ? (
                <React.Fragment>
                  <CompressIcon />
                  Compress
                </React.Fragment>
              ) : (
                <React.Fragment>
                  <ExpandIcon />
                  Expand
                </React.Fragment>
              )}
            </Button>
          </FlexItem>
        </Flex>
      </div>
    );
  }
}
